// Liquidación de contratos — v0.2 (sin duplicado, dividida)

function calcBruto(c) {
  let bruto = c.honorarios;
  if (c.horas > 40) {
    bruto = bruto + (c.horas - 40) * c.tarifa * 1.5;
  }
  return bruto;
}

function calcRetencion(bruto) {
  return bruto > 5000 ? bruto * 0.10 : 0;
}

function formatBoletaLiquida(nombre, bruto, retencion, neto) {
  let s = '';
  s = s + 'Empleado: ' + nombre + '\\n';
  s = s + 'Bruto: $' + bruto.toFixed(2) + '\\n';
  s = s + 'Retención: $' + retencion.toFixed(2) + '\\n';
  s = s + 'Neto: $' + neto.toFixed(2) + '\\n';
  return s;
}

function liquidarContrato(c) {
  const bruto = calcBruto(c);
  const retencion = calcRetencion(bruto);
  const neto = bruto - retencion;
  const boleta = formatBoletaLiquida(c.nombre, bruto, retencion, neto);
  return { bruto, neto, retencion, boleta };
}

function liquidarYResumir(c) {
  const r = liquidarContrato(c);
  return formatBoletaLiquida(c.nombre, r.bruto, r.retencion, r.neto) + 'Estado: LIQUIDADO\\n';
}

