const c = { nombre: 'Ana', honorarios: 3000, horas: 40, tarifa: 50 };
const r = liquidarContrato(c);
if (r.retencion !== 0) throw new Error('No debe haber retención bajo $5000');
if (Math.abs(r.neto - 3000) > 0.01) throw new Error('Neto debe ser igual al bruto');

const c = { nombre: 'Beto', honorarios: 6000, horas: 40, tarifa: 50 };
const r = liquidarContrato(c);
if (Math.abs(r.retencion - 600) > 0.01) throw new Error('Retención debe ser 600');
if (Math.abs(r.neto - 5400) > 0.01) throw new Error('Neto debe ser 5400');

const c = { nombre: 'Carla', honorarios: 2000, horas: 35, tarifa: 40 };
const r = liquidarContrato(c);
if (!r.boleta.includes('Carla')) throw new Error('La boleta debe incluir el nombre');

const c = { nombre: 'Dani', honorarios: 4000, horas: 40, tarifa: 50 };
const r = liquidarYResumir(c);
if (!r.includes('LIQUIDADO')) throw new Error('El resumen debe indicar LIQUIDADO');
